/**
 * Stripe Configuration and Utilities
 */
import Stripe from 'stripe'

// ============================================================================
// Configuration Types
// ============================================================================

export interface StripeConfigValidation {
  valid: boolean
  missing: string[]
  configured: string[]
}

// ============================================================================
// Stripe Client Initialization
// ============================================================================

let stripeClient: Stripe | null = null

export function getStripe(): Stripe {
  if (!stripeClient) {
    if (!process.env.STRIPE_SECRET_KEY) {
      throw new Error('STRIPE_SECRET_KEY is required. Set it in environment variables or Railway dashboard.')
    }
    stripeClient = new Stripe(process.env.STRIPE_SECRET_KEY, {
      typescript: true,
    })
  }
  return stripeClient
}

// Export as stripe for backward compatibility
export const stripe = {
  get checkout() { return getStripe().checkout },
  get customers() { return getStripe().customers },
  get subscriptions() { return getStripe().subscriptions },
  get billingPortal() { return getStripe().billingPortal },
  get webhooks() { return getStripe().webhooks },
}

// ============================================================================
// Price ID Mappings (safe access with optional chaining)
// ============================================================================

const getPriceId = (envVar: string | undefined): string | undefined => envVar

