/**
 * Validates that all required Stripe environment variables are configured.
 * Call this during app startup to fail fast with clear error messages.
 */
export function validateStripeConfig(): StripeConfigValidation {
  const required: Record<string, string | undefined> = {
    // Core Stripe config
    STRIPE_SECRET_KEY: process.env.STRIPE_SECRET_KEY,
    STRIPE_WEBHOOK_SECRET: process.env.STRIPE_WEBHOOK_SECRET,
    // Option C Subscription tiers
    STRIPE_PRICE_TIER_PRO: process.env.STRIPE_PRICE_TIER_PRO,
    STRIPE_PRICE_TIER_TEAM: process.env.STRIPE_PRICE_TIER_TEAM,
    STRIPE_PRICE_TIER_PRO_ANNUAL: process.env.STRIPE_PRICE_TIER_PRO_ANNUAL,
    STRIPE_PRICE_TIER_TEAM_ANNUAL: process.env.STRIPE_PRICE_TIER_TEAM_ANNUAL,
    // Legacy tiers
    STRIPE_PRICE_TIER_MAX: process.env.STRIPE_PRICE_TIER_MAX,
    STRIPE_PRICE_TIER_MAX_ANNUAL: process.env.STRIPE_PRICE_TIER_MAX_ANNUAL,
    // One-time packs (Option C)
    STRIPE_PRICE_ONETIME_20: process.env.STRIPE_PRICE_ONETIME_20,
    STRIPE_PRICE_ONETIME_50: process.env.STRIPE_PRICE_ONETIME_50,
    STRIPE_PRICE_ONETIME_100: process.env.STRIPE_PRICE_ONETIME_100,
    STRIPE_PRICE_ONETIME_200: process.env.STRIPE_PRICE_ONETIME_200,
    // Overflow credits (legacy)
    STRIPE_PRICE_OVERFLOW_PRO_10: process.env.STRIPE_PRICE_OVERFLOW_PRO_10,
    STRIPE_PRICE_OVERFLOW_PRO_25: process.env.STRIPE_PRICE_OVERFLOW_PRO_25,
    STRIPE_PRICE_OVERFLOW_PRO_50: process.env.STRIPE_PRICE_OVERFLOW_PRO_50,
    STRIPE_PRICE_OVERFLOW_MAX_50: process.env.STRIPE_PRICE_OVERFLOW_MAX_50,
    STRIPE_PRICE_OVERFLOW_MAX_100: process.env.STRIPE_PRICE_OVERFLOW_MAX_100,
    // Gift packs (legacy)
    STRIPE_PRICE_GIFT_10: process.env.STRIPE_PRICE_GIFT_10,
    STRIPE_PRICE_GIFT_30: process.env.STRIPE_PRICE_GIFT_30,
    STRIPE_PRICE_GIFT_100: process.env.STRIPE_PRICE_GIFT_100,
  }

  const missing: string[] = []
  const configured: string[] = []

  for (const [key, value] of Object.entries(required)) {
    if (value) {
      configured.push(key)
    } else {
      missing.push(key)
    }
  }

  return {
    valid: missing.length === 0,
    missing,
    configured,
  }
}

/**
 * Gets a detailed validation error message for display/logging
 */
export function getStripeConfigErrorMessage(validation: StripeConfigValidation): string {
  if (validation.valid) {
    return 'All Stripe environment variables are configured.'
  }

  return `Missing Stripe configuration:\n${validation.missing.map(key => `  - ${key}`).join('\n')}\n\nConfigure these in your .env file or Railway dashboard.`
}

// Reverse lookup: Price ID -> Tier ID (works for both monthly and annual)
export function getTierIdFromPriceId(priceId: string): string | null {
  // Check monthly prices
  for (const [tierId, stripePriceId] of Object.entries(STRIPE_PRICES.subscriptions.monthly)) {
    if (stripePriceId === priceId) return tierId
  }
  // Check annual prices
  for (const [tierId, stripePriceId] of Object.entries(STRIPE_PRICES.subscriptions.annual)) {
    if (stripePriceId === priceId) return tierId
  }
  return null
}

// Get Stripe price ID for a tier (supports billing period)
export function getStripePriceId(tierId: string, billing: 'monthly' | 'annual' = 'monthly'): string | null {
  const prices = STRIPE_PRICES.subscriptions[billing]
  return prices[tierId as keyof typeof prices] ?? null
}

