/**
 * POST /api/stripe/webhook
 * Handles all Stripe webhook events with idempotency
 */
import { NextRequest, NextResponse } from 'next/server'
import { headers } from 'next/headers'
import Stripe from 'stripe'
import { stripe, getTierIdFromPriceId } from '@/lib/stripe'
import { prisma } from '@/lib/prisma'
import { getSubscriptionTier } from '@/lib/pricing'
import { getUserIdFromStripeCustomer } from '@/lib/stripe-customer'

/**
 * Idempotency check using Stripe event ID
 * Prevents duplicate processing when Stripe retries webhooks
 */
async function isEventProcessed(eventId: string): Promise<boolean> {
  const existing = await prisma.transaction.findFirst({
    where: {
      metadata: {
        path: ['stripeEventId'],
        equals: eventId,
      },
    },
    select: { id: true },
  })
  return !!existing
}

/**
 * Mark an event as processed by storing its ID in a transaction record
 */
async function markEventProcessed(
  eventId: string,
  eventType: string,
  userId: string,
  metadata: Record<string, unknown>
): Promise<void> {
  await prisma.transaction.create({
    data: {
      userId,
      type: `WEBHOOK_${eventType.toUpperCase().replace(/\./g, '_')}`,
      amount: 0,
      description: `Webhook processed: ${eventType}`,
      metadata: {
        stripeEventId: eventId,
        ...metadata,
      },
    },
  })
}

export async function POST(request: NextRequest) {
  const body = await request.text()
  const headersList = await headers()
  const signature = headersList.get('stripe-signature')

  if (!signature) {
    return NextResponse.json({ error: 'Missing signature' }, { status: 400 })
  }

  let event: Stripe.Event

  try {
    event = stripe.webhooks.constructEvent(
      body,
      signature,
      process.env.STRIPE_WEBHOOK_SECRET!
    )
  } catch (err) {
    console.error('Webhook signature verification failed:', err)
    return NextResponse.json({ error: 'Invalid signature' }, { status: 400 })
  }

  // Idempotency check: skip if we've already processed this event
  if (await isEventProcessed(event.id)) {
    console.log(`Event ${event.id} already processed, skipping`)
    return NextResponse.json({ received: true, duplicate: true })
  }

  try {
    switch (event.type) {
      case 'checkout.session.completed': {
        const session = event.data.object as Stripe.Checkout.Session
        // Handle credit pack purchases (one-time payments)
        if (session.metadata?.type === 'credit_pack' && session.payment_status === 'paid') {
          await handleCreditPackPurchase(session, event.id)
        }
        break
      }

      case 'customer.subscription.created': {
        const subscription = event.data.object as Stripe.Subscription
        await handleSubscriptionCreated(subscription, event.id)
        break
      }

      case 'customer.subscription.updated': {
        const subscription = event.data.object as Stripe.Subscription
        await handleSubscriptionUpdated(subscription, event.id)
        break
      }

      case 'customer.subscription.deleted': {
        const subscription = event.data.object as Stripe.Subscription
        await handleSubscriptionDeleted(subscription, event.id)
        break
      }

      case 'invoice.paid': {
        const invoice = event.data.object as Stripe.Invoice & { subscription?: string | { id: string } }
        // subscription can be a string ID or expanded object
        const subscriptionId = typeof invoice.subscription === 'string'
          ? invoice.subscription
          : invoice.subscription?.id
        if (subscriptionId) {
          await handleInvoicePaid(invoice, subscriptionId, event.id)
        }
        break
      }

      case 'invoice.payment_failed': {
        const invoice = event.data.object as Stripe.Invoice & { subscription?: string | { id: string } }
        await handleInvoicePaymentFailed(invoice, event.id)
        break
      }

      default:
        console.log(`Unhandled event type: ${event.type}`)
    }

    return NextResponse.json({ received: true })
  } catch (error) {
    console.error(`Webhook handler error for ${event.type}:`, error)
    return NextResponse.json({ error: 'Webhook handler failed' }, { status: 500 })
  }
}

// ===== Handler Functions =====

async function handleSubscriptionCreated(subscription: Stripe.Subscription, eventId: string) {
  const customerId = typeof subscription.customer === 'string'
    ? subscription.customer
    : subscription.customer.id
  const userId = subscription.metadata?.userId || await getUserIdFromStripeCustomer(customerId)

  if (!userId) {
    console.error('Cannot find user for subscription:', subscription.id)
    await markEventProcessed(eventId, 'subscription.created', 'unknown', { error: 'User not found', subscriptionId: subscription.id })
    return
  }

  const priceId = subscription.items.data[0]?.price?.id ?? ''
  const tierId = subscription.metadata?.tierId || getTierIdFromPriceId(priceId) || 'tier_pro'
  const tier = getSubscriptionTier(tierId)

  // Cast to access timestamp fields
  const sub = subscription as unknown as {
    current_period_start: number
    current_period_end: number
    cancel_at_period_end: boolean
    status: string
    id: string
    metadata?: { userId?: string; tierId?: string }
  }

  await prisma.subscription.upsert({
    where: { userId },
    create: {
      userId,
      stripeSubscriptionId: subscription.id,
      stripePriceId: priceId,
      status: subscription.status,
      tierId,
      analysesPerMonth: tier?.monthlyCredits ?? 30,
      analysesUsedThisMonth: 0,
      currentPeriodStart: new Date(sub.current_period_start * 1000),
      currentPeriodEnd: new Date(sub.current_period_end * 1000),
      cancelAtPeriodEnd: sub.cancel_at_period_end,
    },
    update: {
      stripeSubscriptionId: subscription.id,
      stripePriceId: priceId,
      status: subscription.status,
      tierId,
      analysesPerMonth: tier?.monthlyCredits ?? 30,
      currentPeriodStart: new Date(sub.current_period_start * 1000),
      currentPeriodEnd: new Date(sub.current_period_end * 1000),
      cancelAtPeriodEnd: sub.cancel_at_period_end,
    },
  })

  // Mark event as processed
  await markEventProcessed(eventId, 'subscription.created', userId, {
    stripeSubscriptionId: subscription.id,
    tierId,
  })

  console.log(`Subscription created for user ${userId}: ${tierId}`)
}

async function handleSubscriptionUpdated(subscription: Stripe.Subscription, eventId: string) {
  // Find subscription by Stripe ID
  const existingSub = await prisma.subscription.findUnique({
    where: { stripeSubscriptionId: subscription.id },
  })

  if (!existingSub) {
    // Might be a new subscription, try to create
    await handleSubscriptionCreated(subscription, eventId)
    return
  }

  const priceId = subscription.items.data[0]?.price?.id ?? existingSub.stripePriceId
  const tierId = getTierIdFromPriceId(priceId) || existingSub.tierId
  const tier = getSubscriptionTier(tierId)

  // Check if plan changed (upgrade/downgrade)
  const planChanged = existingSub.stripePriceId !== priceId

  // Cast to access timestamp fields
  const sub = subscription as unknown as {
    current_period_start: number
    current_period_end: number
    cancel_at_period_end: boolean
  }

  await prisma.subscription.update({
    where: { stripeSubscriptionId: subscription.id },
    data: {
      stripePriceId: priceId,
      status: subscription.status,
      tierId,
      analysesPerMonth: tier?.monthlyCredits ?? existingSub.analysesPerMonth,
      currentPeriodStart: new Date(sub.current_period_start * 1000),
      currentPeriodEnd: new Date(sub.current_period_end * 1000),
      cancelAtPeriodEnd: sub.cancel_at_period_end,
      // Reset usage on plan change
      ...(planChanged ? { analysesUsedThisMonth: 0 } : {}),
    },
  })

  if (planChanged) {
    await prisma.transaction.create({
      data: {
        userId: existingSub.userId,
        type: 'SUBSCRIPTION_CHANGED',
        amount: 0,
        description: `Changed to ${tier?.name ?? tierId}`,
        metadata: {
          stripeEventId: eventId,
          stripeSubscriptionId: subscription.id,
          fromTierId: existingSub.tierId,
          toTierId: tierId,
        },
      },
    })
  }

  // Mark event as processed
  await markEventProcessed(eventId, 'subscription.updated', existingSub.userId, {
    stripeSubscriptionId: subscription.id,
    tierId,
    planChanged,
  })

  console.log(`Subscription updated: ${subscription.id}, status: ${subscription.status}`)
}

async function handleSubscriptionDeleted(subscription: Stripe.Subscription, eventId: string) {
  const existingSub = await prisma.subscription.findUnique({
    where: { stripeSubscriptionId: subscription.id },
  })

  if (!existingSub) {
    await markEventProcessed(eventId, 'subscription.deleted', 'unknown', { error: 'Subscription not found', subscriptionId: subscription.id })
    return
  }

  await prisma.subscription.update({
    where: { stripeSubscriptionId: subscription.id },
    data: {
      status: 'canceled',
    },
  })

  await prisma.transaction.create({
    data: {
      userId: existingSub.userId,
      type: 'SUBSCRIPTION_CANCELED',
      amount: 0,
      description: 'Subscription canceled',
      metadata: {
        stripeEventId: eventId,
        stripeSubscriptionId: subscription.id,
        tierId: existingSub.tierId,
      },
    },
  })

  console.log(`Subscription canceled: ${subscription.id}`)
}

async function handleInvoicePaid(invoice: Stripe.Invoice, subscriptionId: string, eventId: string) {
  // This handles subscription renewals
  const existingSub = await prisma.subscription.findUnique({
    where: { stripeSubscriptionId: subscriptionId },
  })

  if (!existingSub) {
    await markEventProcessed(eventId, 'invoice.paid', 'unknown', { error: 'Subscription not found', subscriptionId })
    return
  }

  // Only reset for paid tiers (not free)
  const isPaidTier = existingSub.tierId !== 'tier_free'

  // Fetch fresh subscription data from Stripe
  const subscription = await stripe.subscriptions.retrieve(subscriptionId)

  // Cast to access timestamp fields
  const sub = subscription as unknown as {
    current_period_start: number
    current_period_end: number
  }

  // Get the tier to know how many credits to grant
  const tier = getSubscriptionTier(existingSub.tierId)
  const monthlyCredits = tier?.monthlyCredits ?? existingSub.analysesPerMonth

  // Reset monthly subscription credits on renewal
  await prisma.subscription.update({
    where: { stripeSubscriptionId: subscriptionId },
    data: {
      analysesUsedThisMonth: 0,
      analysesPerMonth: monthlyCredits,  // Update in case tier changed
      currentPeriodStart: new Date(sub.current_period_start * 1000),
      currentPeriodEnd: new Date(sub.current_period_end * 1000),
      status: 'active',
    },
  })

  // Reset credit balance for paid subscribers with transactional safety
  if (isPaidTier) {
    await prisma.$transaction(async (tx) => {
      const currentCredits = await tx.credits.findUnique({
        where: { userId: existingSub.userId },
      })

      if (!currentCredits) {
        await tx.credits.create({
          data: {
            userId: existingSub.userId,
            balance: monthlyCredits,
            lifetimeCredits: monthlyCredits,
            lifetimeSpent: 0,
          },
        })
      } else {
        await tx.credits.update({
          where: { userId: existingSub.userId },
          data: {
            balance: currentCredits.balance + monthlyCredits,
            lifetimeCredits: currentCredits.lifetimeCredits + monthlyCredits,
          },
        })
      }
    })
  }

  // Record transaction
  await prisma.transaction.create({
    data: {
      userId: existingSub.userId,
      type: 'SUBSCRIPTION_RENEWAL',
      amount: invoice.amount_paid ?? 0,
      description: `Subscription renewed: ${existingSub.tierId} (${monthlyCredits} credits)`,
      metadata: {
        stripeEventId: eventId,
        stripeInvoiceId: invoice.id,
        stripeSubscriptionId: subscriptionId,
        creditsGranted: monthlyCredits,
      },
    },
  })

  console.log(`Subscription renewed for user ${existingSub.userId}: ${monthlyCredits} credits`)
}

async function handleInvoicePaymentFailed(invoice: Stripe.Invoice & { subscription?: string | { id: string } }, eventId: string) {
  const subscriptionId = typeof invoice.subscription === 'string'
    ? invoice.subscription
    : invoice.subscription?.id

  if (!subscriptionId) {
    await markEventProcessed(eventId, 'invoice.payment_failed', 'unknown', { error: 'No subscription ID', invoiceId: invoice.id })
    return
  }

  const existingSub = await prisma.subscription.findUnique({
    where: { stripeSubscriptionId: subscriptionId },
  })

  if (!existingSub) {
    await markEventProcessed(eventId, 'invoice.payment_failed', 'unknown', { error: 'Subscription not found', subscriptionId })
    return
  }

  // Update subscription status
  await prisma.subscription.update({
    where: { stripeSubscriptionId: subscriptionId },
    data: { status: 'past_due' },
  })

  await prisma.transaction.create({
    data: {
      userId: existingSub.userId,
      type: 'PAYMENT_FAILED',
      amount: invoice.amount_due ?? 0,
      description: 'Payment failed',
      metadata: {
        stripeEventId: eventId,
        stripeInvoiceId: invoice.id,
        stripeSubscriptionId: subscriptionId,
      },
    },
  })

  console.log(`Payment failed for subscription: ${subscriptionId}`)
}

async function handleCreditPackPurchase(session: Stripe.Checkout.Session, eventId: string) {
  const userId = session.metadata?.userId
  const packId = session.metadata?.packId
  const credits = parseInt(session.metadata?.credits || '0', 10)

  if (!userId || !packId || credits <= 0) {
    console.error('Invalid credit pack purchase metadata:', session.metadata)
    await markEventProcessed(eventId, 'checkout.session.completed', 'unknown', {
      error: 'Invalid metadata',
      metadata: session.metadata,
    })
    return
  }

  // Add credits to user's balance with transactional safety
  await prisma.$transaction(async (tx) => {
    const currentCredits = await tx.credits.findUnique({
      where: { userId },
    })

    if (!currentCredits) {
      await tx.credits.create({
        data: {
          userId,
          balance: credits,
          lifetimeCredits: credits,
          lifetimeSpent: 0,
        },
      })
    } else {
      await tx.credits.update({
        where: { userId },
        data: {
          balance: currentCredits.balance + credits,
          lifetimeCredits: currentCredits.lifetimeCredits + credits,
        },
      })
    }
  })

  // Record transaction
  await prisma.transaction.create({
    data: {
      userId,
      type: 'CREDIT_PURCHASE',
      amount: session.amount_total ?? 0,
      description: `Purchased ${credits} credits (${packId})`,
      metadata: {
        stripeEventId: eventId,
        stripeSessionId: session.id,
        packId,
        credits,
      },
    },
  })

  console.log(`Credit pack purchased for user ${userId}: ${credits} credits (${packId})`)
}

/**
 * POST /api/stripe/checkout/subscription
 * Creates a Stripe Checkout session for subscription
 */
import { NextRequest, NextResponse } from 'next/server'
import { auth } from '@/lib/auth'
import { stripe, getStripePriceId } from '@/lib/stripe'
import { getOrCreateStripeCustomer } from '@/lib/stripe-customer'
import { getSubscriptionTier } from '@/lib/pricing'

export async function POST(request: NextRequest) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 })
    }

    const { tierId, billing = 'monthly' } = await request.json()

    // Validate billing period
    if (billing !== 'monthly' && billing !== 'annual') {
      return NextResponse.json({ success: false, error: 'Invalid billing period' }, { status: 400 })
    }

    // Validate tier (exclude starter tier - it's free)
    const tier = getSubscriptionTier(tierId)
    if (!tier || tierId === 'tier_starter') {
      return NextResponse.json({ success: false, error: 'Invalid tier' }, { status: 400 })
    }

    // Handle enterprise tier - redirect to contact
    if (tierId === 'tier_enterprise') {
      return NextResponse.json({ 
        success: false, 
        error: 'Enterprise tier requires custom setup. Please contact sales.' 
      }, { status: 400 })
    }

    const priceId = getStripePriceId(tierId, billing)
    if (!priceId) {
      return NextResponse.json({ success: false, error: 'Tier not configured in Stripe' }, { status: 400 })
    }

    // Get or create Stripe customer
    const customerId = await getOrCreateStripeCustomer(session.user.id)

    // Create checkout session
    const checkoutSession = await stripe.checkout.sessions.create({
      customer: customerId,
      mode: 'subscription',
      payment_method_types: ['card'],
      line_items: [
        {
          price: priceId,
          quantity: 1,
        },
      ],
      success_url: `${process.env.NEXT_PUBLIC_APP_URL}/dashboard?subscription=success&session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/pricing?subscription=cancelled`,
      subscription_data: {
        metadata: {
          userId: session.user.id,
          tierId,
          billing,
        },
      },
      metadata: {
        userId: session.user.id,
        tierId,
        billing,
        type: 'subscription',
      },
    })

    return NextResponse.json({
      success: true,
      data: { url: checkoutSession.url },
    })
  } catch (error) {
    console.error('Subscription checkout error:', error)
    return NextResponse.json({ success: false, error: 'Failed to create checkout' }, { status: 500 })
  }
}

/**
 * Pricing Page - Option C
 * Subscription Tiers: Free, Pro, Max, Enterprise
 * One-Time Packs: Available to all
 */

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useSession } from 'next-auth/react'
import { Check, X, Sparkles, Zap, Users, Building2, Loader2, Package } from 'lucide-react'
import { SUBSCRIPTION_TIERS, ONE_TIME_PACKS, FEATURE_COMPARISON } from '@/lib/pricing'
import { toast } from '@/hooks/use-toast'
import { HintTooltip } from "@/components/ui/hint-tooltip"

// Icon mapping for tiers - Option C
const TIER_ICONS: Record<string, typeof Sparkles> = {
  tier_free: Sparkles,
  tier_pro: Zap,
  tier_max: Users,
  tier_enterprise: Building2,
}

export default function PricingPage() {
  const router = useRouter()
  const { data: session } = useSession()
  const [loadingTier, setLoadingTier] = useState<string | null>(null)
  const [loadingPack, setLoadingPack] = useState<string | null>(null)
  const [billing, setBilling] = useState<'monthly' | 'annual'>('monthly')

  const handleSubscribe = async (tierId: string) => {
    // Free tier goes to signup
    if (tierId === 'tier_free') {
      router.push('/auth/signup')
      return
    }

    // Not logged in - redirect to signup with plan
    if (!session) {
      router.push(`/auth/signup?plan=${tierId}`)
      return
    }

    // Logged in - initiate Stripe checkout
    setLoadingTier(tierId)
    try {
      const response = await fetch('/api/stripe/checkout/subscription', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ tierId, billing }),
      })
      const data = await response.json()

      if (data.success && data.data.url) {
        window.location.href = data.data.url
      } else {
        toast.error(data.error || 'Failed to start checkout')
      }
    } catch (error) {
      console.error('Checkout error:', error)
      toast.error('Failed to start checkout. Please try again.')
    } finally {
      setLoadingTier(null)
    }
  }

  const handleBuyPack = async (packId: string) => {
