/**
 * Stripe Customer Management
 * Creates and manages Stripe customers linked to users
 */
import { stripe } from './stripe'
import { prisma } from './prisma'

/**
 * Get or create a Stripe customer for a user
 * Creates on first purchase/subscription (lazy creation)
 */
export async function getOrCreateStripeCustomer(userId: string): Promise<string> {
  // Check if user already has a Stripe customer
  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: { id: true, email: true, name: true, stripeCustomerId: true },
  })

  if (!user) {
    throw new Error('User not found')
  }

  // Return existing customer ID
  if (user.stripeCustomerId) {
    return user.stripeCustomerId
  }

  // Create new Stripe customer
  const customer = await stripe.customers.create({
    email: user.email ?? undefined,
    name: user.name ?? undefined,
    metadata: {
      userId: user.id,
    },
  })

  // Store customer ID in database
  await prisma.user.update({
    where: { id: userId },
    data: { stripeCustomerId: customer.id },
  })

  return customer.id
}

/**
 * Get user ID from Stripe customer ID
 */
export async function getUserIdFromStripeCustomer(customerId: string): Promise<string | null> {
  const user = await prisma.user.findUnique({
    where: { stripeCustomerId: customerId },
    select: { id: true },
  })
  return user?.id ?? null
}

/**
 * Get user by Stripe customer ID
 */
export async function getUserByStripeCustomer(customerId: string) {
  return prisma.user.findUnique({
    where: { stripeCustomerId: customerId },
    include: { subscription: true },
  })
}

/**
 * Credits Service
 * Handles all credit operations: balance checks, purchases, deductions
 */

import { prisma } from './prisma'
import {
  CREDIT_PACKS,
  SUBSCRIPTION_TIERS,
  FREE_TIER_LIMITS,
  CREDIT_COSTS,
  getCreditPack,
  getSubscriptionTier,
  getSubscriberPackPrice,
} from './pricing'

/**
 * Ensure user exists in database before performing credit operations
 * Uses upsert to avoid race conditions with concurrent requests
 */
async function ensureUserExistsForCredits(userId: string, email?: string | null) {
  try {
    // Use upsert for atomic operation - eliminates race condition
    const user = await prisma.user.upsert({
      where: { id: userId },
      create: {
        id: userId,
        email: email,
      },
      update: {
        // Update email if provided and different
        ...(email ? { email } : {}),
      },
    })
    return user.id
  } catch (error) {
    // Handle unique constraint violation on email (user exists with different ID)
    if (error instanceof Error && error.message.includes('Unique constraint')) {
      if (email) {
        const userByEmail = await prisma.user.findUnique({
          where: { email },
        })
        if (userByEmail) {
          return userByEmail.id
        }
      }
    }
    console.error('Failed to ensure user exists for credits:', error)
    return userId
  }
}

