// ============================================================================
// Reserve-Confirm-Cancel Pattern for Analysis Credits
// ============================================================================
// This pattern ensures credits are properly managed even if analysis fails:
// 1. reserveCreditsForAnalysis() - Deducts credits and creates PENDING transaction
// 2. confirmCreditReservation() - Marks transaction as CONFIRMED after success
// 3. cancelCreditReservation() - Refunds credits and marks as CANCELLED on failure

/**
 * Reserve credits for an analysis (creates PENDING transaction)
 * Credits are deducted immediately but can be refunded if analysis fails
 *
 * IMPORTANT: All validation and deduction happens atomically inside the transaction
 * to prevent race conditions where two concurrent requests could both pass validation
 * and then both deduct credits, causing negative balance.
 */
export async function reserveCreditsForAnalysis(
  userId: string,
  analysisId: string,
  userEmail?: string | null
): Promise<ReserveResult> {
  // Ensure user exists
  const effectiveUserId = await ensureUserExistsForCredits(userId, userEmail)
  const cost = CREDIT_COSTS.FULL_ANALYSIS

  // All validation and deduction inside transaction for atomicity
  return await prisma.$transaction(async (tx) => {
    // Check subscription first (inside transaction)
    const subscription = await tx.subscription.findUnique({
      where: { userId: effectiveUserId },
    })

    if (subscription?.status === 'active' &&
        subscription.analysesUsedThisMonth < subscription.analysesPerMonth) {
      // Reserve from subscription atomically
      await tx.subscription.update({
        where: { userId: effectiveUserId },
        data: {
          analysesUsedThisMonth: { increment: 1 },
        },
      })

      const transaction = await tx.transaction.create({
        data: {
          userId: effectiveUserId,
          type: 'SUBSCRIPTION_USE',
          amount: 0,
          description: 'Analysis (subscription)',
          status: 'PENDING',
          analysisId: analysisId,
        },
      })

      return {
        success: true,
        reservationId: transaction.id,
        source: 'subscription' as const,
      }
    }

    // Check purchased credits (inside transaction)
    const credits = await tx.credits.findUnique({
      where: { userId: effectiveUserId },
    })

    if (credits && credits.balance >= cost) {
      // Atomic update with balance re-check to prevent race condition
      const updated = await tx.credits.updateMany({
        where: {
          userId: effectiveUserId,
          balance: { gte: cost }, // Re-verify balance atomically
        },
        data: {
          balance: { decrement: cost },
          lifetimeSpent: { increment: cost },
        },
      })

      if (updated.count === 0) {
        // Race condition: another request deducted credits between check and update
        throw new Error('Insufficient credits (concurrent modification)')
      }

      const transaction = await tx.transaction.create({
        data: {
          userId: effectiveUserId,
          type: 'SPEND',
          amount: -cost,
          description: `Analysis (${cost} credits)`,
          status: 'PENDING',
          analysisId: analysisId,
        },
      })

      return {
        success: true,
        reservationId: transaction.id,
        source: 'credits' as const,
      }
    }

    // Check free tier (inside transaction)
    if (!subscription || subscription.status !== 'active') {
      const today = new Date().toISOString().split('T')[0]
      const dailyFree = await tx.dailyFreeAnalysis.findUnique({
        where: { userId: effectiveUserId },
      })

      // Can use free if: no record, different date, or under limit
      if (!dailyFree || dailyFree.date !== today || dailyFree.count < FREE_TIER_LIMITS.MONTHLY_ANALYSES) {
        await tx.dailyFreeAnalysis.upsert({
          where: { userId: effectiveUserId },
          create: {
            userId: effectiveUserId,
            date: today,
            count: 1,
          },
          update: {
            date: today,
            count: { increment: 1 },
          },
        })

        const transaction = await tx.transaction.create({
          data: {
            userId: effectiveUserId,
            type: 'FREE_USE',
            amount: 0,
            description: 'Free analysis',
            status: 'PENDING',
            analysisId: analysisId,
          },
        })

        return {
          success: true,
          reservationId: transaction.id,
          source: 'free' as const,
        }
      }
    }

    // No valid source found - insufficient credits
    const reason = subscription?.status === 'active'
      ? 'You have used all your subscription credits this month. Purchase additional credits to continue.'
      : `You need ${cost} credits for an analysis. Subscribe or purchase credits to continue.`

    return {
      success: false,
      error: reason,
    }
  }, {
    isolationLevel: 'Serializable', // Strongest isolation for financial operations
  })
}

