/**
 * Stripe Integration Test Script
 * Tests the complete Stripe subscription flow
 * 
 * Usage: npx tsx scripts/test-stripe-integration.ts
 */

import { prisma } from '../src/lib/prisma'
import { SUBSCRIPTION_TIERS, getSubscriptionTier } from '../src/lib/pricing'
import { TIER_CONFIG } from '../src/lib/stripe'

async function testStripeIntegration() {
  console.log('🧪 Testing Stripe Integration...\n')

  let passed = 0
  let failed = 0

  // Test 1: Verify tier configuration
  console.log('Test 1: Verify tier configuration')
  const expectedTiers = ['tier_free', 'tier_pro', 'tier_team', 'tier_enterprise']
  const actualTiers = SUBSCRIPTION_TIERS.map(t => t.id)

  for (const tier of expectedTiers) {
    if (actualTiers.includes(tier)) {
      console.log(`  ✅ ${tier} configured`)
      passed++
    } else {
      console.log(`  ❌ ${tier} missing`)
      failed++
    }
  }

  // Test 2: Verify pricing
  console.log('\nTest 2: Verify pricing')
  const pricingTests = [
    { tier: 'tier_free', expected: 0 },
    { tier: 'tier_pro', expected: 1900 },
    { tier: 'tier_team', expected: 9900 },
    { tier: 'tier_enterprise', expected: 49900 },
  ]

  for (const test of pricingTests) {
    const tier = getSubscriptionTier(test.tier)
    if (tier && tier.price === test.expected) {
      console.log(`  ✅ ${test.tier}: $${test.expected / 100}`)
      passed++
    } else {
      console.log(`  ❌ ${test.tier}: Expected ${test.expected}, got ${tier?.price}`)
      failed++
    }
  }

  // Test 3: Verify credit allocations
  console.log('\nTest 3: Verify monthly analyses')
  const creditTests = [
    { tier: 'tier_free', expected: 5 },
    { tier: 'tier_pro', expected: 100 },
    { tier: 'tier_team', expected: 500 },
    { tier: 'tier_enterprise', expected: 0 }, // Unlimited
  ]

  for (const test of creditTests) {
    const tier = getSubscriptionTier(test.tier)
    if (tier && tier.monthlyCredits === test.expected) {
      console.log(`  ✅ ${test.tier}: ${test.expected === 0 ? 'Unlimited' : test.expected}/month`)
      passed++
    } else {
      console.log(`  ❌ ${test.tier}: Expected ${test.expected}, got ${tier?.monthlyCredits}`)
      failed++
    }
  }

  // Test 4: Verify API access
  console.log('\nTest 4: Verify API access')
  const apiAccessTests = [
    { tier: 'tier_free', expected: false },
    { tier: 'tier_pro', expected: false },
    { tier: 'tier_team', expected: true },
    { tier: 'tier_enterprise', expected: true },
  ]

  for (const test of apiAccessTests) {
    const tier = getSubscriptionTier(test.tier)
    if (tier && tier.apiAccess === test.expected) {
      console.log(`  ✅ ${test.tier}: API access = ${test.expected}`)
      passed++
    } else {
      console.log(`  ❌ ${test.tier}: Expected API access = ${test.expected}, got ${tier?.apiAccess}`)
      failed++
    }
  }

  // Test 5: Verify TIER_CONFIG
  console.log('\nTest 5: Verify TIER_CONFIG')
  const configTiers = ['tier_free', 'tier_pro', 'tier_team', 'tier_enterprise']
  for (const tier of configTiers) {
    if (tier in TIER_CONFIG) {
      console.log(`  ✅ ${tier} in TIER_CONFIG`)
      passed++
    } else {
      console.log(`  ❌ ${tier} missing from TIER_CONFIG`)
      failed++
    }
  }

  // Test 6: Database schema check
  console.log('\nTest 6: Verify database schema')
  try {
    const subscription = await prisma.subscription.findFirst()
    console.log(`  ✅ Subscription table accessible`)
    passed++

    const user = await prisma.user.findFirst()
    console.log(`  ✅ User table accessible`)
    passed++

    const credits = await prisma.credits.findFirst()
    console.log(`  ✅ Credits table accessible`)
    passed++
  } catch (error) {
    console.log(`  ❌ Database error: ${error}`)
    failed += 3
  }

  // Summary
  console.log('\n' + '='.repeat(50))
  console.log(`Test Results: ${passed} passed, ${failed} failed`)
  console.log('='.repeat(50))

  if (failed === 0) {
    console.log('\n✅ All tests passed! Stripe integration is ready.')
    process.exit(0)
  } else {
    console.log('\n❌ Some tests failed. Please review the configuration.')
    process.exit(1)
  }
}

testStripeIntegration().catch(console.error)
EOF
echo "✅ Created test script"

